    BANCO["nervios_craneales"]["preguntas"].append({"id": "nervios_craneales_auto_b349ac03", "concepto": "Síndrome del seno cavernoso", "enunciado": "Una mujer de 55 años presenta oftalmoplejía completa del ojo izquierdo, ptosis, midriasis arreactiva y anestesia en territorio frontal y maxilar izquierdos, con agudeza visual conservada. ¿Cuál es la localización más probable de la lesión?", "opciones": {"A": "Fisura orbitaria superior izquierda", "B": "Seno cavernoso izquierdo", "C": "Vértice orbitario izquierdo", "D": "Ángulo pontocerebeloso izquierdo"}, "correcta": "B", "exp": "La afectación de los pares III, IV, VI y de las ramas V1 y V2 del trigémino con agudeza visual conservada (nervio óptico indemne) localiza la lesión en el seno cavernoso. En el vértice orbitario o fisura orbitaria superior no se afectaría V2, que pasa por el agujero redondo mayor."})

