    BANCO["disco_intervertebral"]["preguntas"].append({"id": "disco_intervertebral_auto_280b9071", "concepto": "estructura del disco intervertebral", "enunciado": "Respecto a la composición histológica y anatómica del disco intervertebral, ¿cuál de las siguientes afirmaciones es CORRECTA?", "opciones": {"A": "El núcleo pulposo es un derivado embriológico de la cresta neural", "B": "El anillo fibroso está compuesto por fibrocartílago dispuesto en láminas concéntricas con fibras de colágeno orientadas oblicuamente y alternantes", "C": "El disco intervertebral está presente entre todas las vértebras desde C1 hasta el sacro", "D": "El núcleo pulposo se encuentra centrado exactamente en el disco a todos los niveles vertebrales"}, "correcta": "B", "exp": "El anillo fibroso está formado por láminas concéntricas de fibrocartílago cuyas fibras de colágeno cambian de orientación oblicua entre láminas adyacentes, lo que confiere resistencia multidireccional. El núcleo pulposo deriva de la notocorda, no existe disco entre C1-C2, y en la región lumbar el núcleo se sitúa más posterior."})

